#include <stdio.h>
#include <stdlib.h>
#include <string.h>

void vec_add_alias(int *a, const int *b, const int *c, int n) {
    for (int i = 0; i < n; i++) {
        a[i] = b[i] + c[i];
    }
}

void vec_add_restrict(int *restrict a, const int *restrict b,
                      const int *restrict c, int n) {
    for (int i = 0; i < n; i++) {
        a[i] = b[i] + c[i];
    }
}

int main(void) {
    int x[] = {1, 2, 3, 4, 5};
    int y[] = {10, 20, 30, 40, 50};
    int result[5];
    int n = 5;

    vec_add_restrict(result, x, y, n);
    printf("restrict : ");
    for (int i = 0; i < n; i++) printf("%d ", result[i]);
    printf("\n");

    int overlap[5] = {1, 2, 3, 4, 5};
    vec_add_alias(overlap + 1, overlap, overlap, 4);
    printf("alias    : ");
    for (int i = 0; i < n; i++) printf("%d ", overlap[i]);
    printf("\n");

    printf("sizeof(int*) : %lu\n", (unsigned long)sizeof(int *));
    printf("restrict est un contrat compilateur, pas une garantie runtime\n");
    return 0;
}

